/*
 * Generated by scripts/build-bundle.mjs.
 * Keeps index.html playable from file:// without ES module loading.
 */
// src/idleUiState.js
const IDLE_STORAGE_KEY = "paulIdleRpg.ui.v1";

const IDLE_UPGRADE_DEFINITIONS = {
  attack: {
    name: "공격력",
    icon: "sword",
    baseLevel: 12,
    baseCost: 2450,
    costStep: 330,
    increasePerLevel: 120,
    increaseLabel: "공격력"
  },
  hp: {
    name: "체력",
    icon: "heart",
    baseLevel: 11,
    baseCost: 2150,
    costStep: 310,
    increasePerLevel: 1100,
    increaseLabel: "체력"
  },
  defense: {
    name: "방어력",
    icon: "shield",
    baseLevel: 10,
    baseCost: 1850,
    costStep: 285,
    increasePerLevel: 55,
    increaseLabel: "방어력"
  }
};

function createIdleUiState(now = Date.now()) {
  return {
    regionName: "별빛 초원",
    stage: 1,
    highestStage: 1,
    stageTitle: "별빛 초원 1-1",
    starDust: 2450,
    starCrystal: 120,
    lastSavedAt: now,
    activeTab: "upgrade",
    notice: "",
    upgrades: Object.fromEntries(
      Object.entries(IDLE_UPGRADE_DEFINITIONS).map(([id, definition]) => [
        id,
        { level: definition.baseLevel }
      ])
    )
  };
}

function normalizeIdleUiState(saved, now = Date.now()) {
  const base = createIdleUiState(now);
  const next = {
    ...base,
    ...saved,
    upgrades: {
      ...base.upgrades,
      ...(saved?.upgrades ?? {})
    }
  };
  next.stage = clampStage(next.stage);
  next.highestStage = Math.max(clampStage(next.highestStage), next.stage);
  next.stageTitle = `${next.regionName} 1-${next.stage}`;
  next.starDust = Math.max(0, Math.floor(Number(next.starDust) || 0));
  next.starCrystal = Math.max(0, Math.floor(Number(next.starCrystal) || 0));
  next.lastSavedAt = Number(next.lastSavedAt) || now;
  return next;
}

function getStageProgress(state) {
  const current = clampStage(state.stage);
  return {
    current,
    total: 10,
    label: `${current}/10`,
    bossCountdown: Math.max(0, 10 - current),
    isBoss: current === 10
  };
}

function getIdleUpgradeRows(state) {
  return Object.entries(IDLE_UPGRADE_DEFINITIONS).map(([id, definition]) => {
    const level = Math.max(definition.baseLevel, state.upgrades?.[id]?.level ?? definition.baseLevel);
    const extraLevels = level - definition.baseLevel;
    const cost = definition.baseCost + extraLevels * definition.costStep;
    const nextIncrease = definition.increasePerLevel * (extraLevels + 1);

    return {
      id,
      name: definition.name,
      icon: definition.icon,
      level,
      levelLabel: `Lv. ${level}`,
      cost,
      canAfford: state.starDust >= cost,
      increaseText: `${definition.increaseLabel} ${formatCompactNumber(nextIncrease)} 증가`
    };
  });
}

function applyIdleUpgrade(state, upgradeId) {
  const row = getIdleUpgradeRows(state).find((item) => item.id === upgradeId);
  if (!row) return { ...state, notice: "준비 중인 강화예요" };
  if (!row.canAfford) return { ...state, notice: "별가루가 부족해요" };

  return {
    ...state,
    starDust: state.starDust - row.cost,
    notice: `${row.name} 강화 완료`,
    upgrades: {
      ...state.upgrades,
      [upgradeId]: {
        level: row.level + 1
      }
    }
  };
}

function calculateOfflineReward(state, now = Date.now()) {
  const elapsedSeconds = Math.max(
    0,
    Math.min(60 * 60 * 8, Math.floor((now - state.lastSavedAt) / 1000))
  );
  const starDust = Math.floor((elapsedSeconds / 60) * Math.max(1, state.highestStage) * 3);

  return {
    elapsedSeconds,
    starDust
  };
}

function formatCompactNumber(value) {
  const number = Math.max(0, Number(value) || 0);
  if (number >= 1_000_000) {
    return `${(number / 1_000_000).toFixed(1).replace(/\.0$/, "")}M`;
  }
  return Math.round(number).toLocaleString("en-US");
}

function clampStage(stage) {
  return Math.min(10, Math.max(1, Math.floor(Number(stage) || 1)));
}


// src/game.js

const starDustEl = document.querySelector("#starDustValue");
const starCrystalEl = document.querySelector("#starCrystalValue");
const stageTitleEl = document.querySelector("#stageTitle");
const stageProgressFillEl = document.querySelector("#stageProgressFill");
const stageProgressLabelEl = document.querySelector("#stageProgressLabel");
const bossCountdownEl = document.querySelector("#bossCountdown");
const upgradeListEl = document.querySelector("#upgradeList");
const bottomNavEl = document.querySelector("#bottomNav");
const offlineNoticeEl = document.querySelector("#offlineNotice");
const settingsButton = document.querySelector("#settingsButton");
const ultimateButton = document.querySelector("#ultimateButton");
const ultimateCutscene = document.querySelector("#ultimateCutscene");

const ULTIMATE_CUTSCENE_CLASS = "is-playing";

let state = loadState();
const offlineReward = calculateOfflineReward(state);

if (offlineReward.starDust > 0) {
  state = {
    ...state,
    starDust: state.starDust + offlineReward.starDust,
    notice: `오프라인 보상 +${formatCompactNumber(offlineReward.starDust)} 별가루`
  };
}

state = { ...state, lastSavedAt: Date.now() };

function loadState() {
  try {
    const saved = JSON.parse(localStorage.getItem(IDLE_STORAGE_KEY));
    return normalizeIdleUiState(saved);
  } catch {
    return createIdleUiState();
  }
}

function saveState() {
  localStorage.setItem(IDLE_STORAGE_KEY, JSON.stringify({
    ...state,
    lastSavedAt: Date.now()
  }));
}

function renderResources() {
  starDustEl.textContent = formatCompactNumber(state.starDust);
  starCrystalEl.textContent = formatCompactNumber(state.starCrystal);
}

function renderStage() {
  const progress = getStageProgress(state);
  stageTitleEl.textContent = state.stageTitle;
  stageProgressLabelEl.textContent = progress.label;
  stageProgressFillEl.style.width = `${(progress.current / progress.total) * 100}%`;
  bossCountdownEl.textContent = String(progress.bossCountdown);
}

function renderUpgradeRows() {
  upgradeListEl.innerHTML = getIdleUpgradeRows(state)
    .map((row) => `
      <article class="upgrade-row ${row.canAfford ? "" : "unaffordable"}">
        <span class="upgrade-icon ${row.icon}" aria-hidden="true"></span>
        <div class="upgrade-copy">
          <strong>${row.name}</strong>
          <span>${row.levelLabel}</span>
          <em>${row.increaseText}</em>
        </div>
        <div class="upgrade-cost">
          <span aria-hidden="true">★</span>
          <strong>${formatCompactNumber(row.cost)}</strong>
        </div>
        <button class="upgrade-button" type="button" data-upgrade-id="${row.id}">
          강화
        </button>
      </article>
    `)
    .join("");
}

function renderNotice() {
  if (!state.notice) {
    offlineNoticeEl.classList.add("hidden");
    offlineNoticeEl.textContent = "";
    return;
  }

  offlineNoticeEl.textContent = state.notice;
  offlineNoticeEl.classList.remove("hidden");
}

function renderTabs() {
  for (const button of bottomNavEl.querySelectorAll("[data-tab]")) {
    button.classList.toggle("active", button.dataset.tab === state.activeTab);
  }
}

function render() {
  state = normalizeIdleUiState(state);
  renderResources();
  renderStage();
  renderUpgradeRows();
  renderTabs();
  renderNotice();
  saveState();
}

upgradeListEl.addEventListener("click", (event) => {
  const button = event.target.closest("[data-upgrade-id]");
  if (!button) return;

  state = applyIdleUpgrade(state, button.dataset.upgradeId);
  render();
});

bottomNavEl.addEventListener("click", (event) => {
  const button = event.target.closest("[data-tab]");
  if (!button) return;

  state = {
    ...state,
    activeTab: button.dataset.tab,
    notice: button.classList.contains("locked")
      ? `${button.innerText.trim()} 준비 중`
      : ""
  };
  render();
});

settingsButton.addEventListener("click", () => {
  state = {
    ...state,
    notice: "설정 UI는 다음 단계에서 연결할게요"
  };
  render();
});

function playUltimateCutscene() {
  if (!ultimateCutscene) return;

  ultimateCutscene.classList.remove(ULTIMATE_CUTSCENE_CLASS);
  void ultimateCutscene.offsetWidth;
  ultimateCutscene.classList.add(ULTIMATE_CUTSCENE_CLASS);
}

if (ultimateButton && ultimateCutscene) {
  ultimateButton.addEventListener("click", playUltimateCutscene);
  ultimateCutscene.addEventListener("animationend", (event) => {
    if (event.animationName === "ultimate-cutscene-in-out") {
      ultimateCutscene.classList.remove(ULTIMATE_CUTSCENE_CLASS);
    }
  });
}

render();

